local function setVisible(window, visible)
    window:SetVisible(visible)
    local count = window:GetChildCount()
    if count == 0 then
        return
    end
    for index = 1, count do
        setVisible(window:GetChildByIndex(index - 1), visible)
    end
end

SystemSettingRecord = {}
