function UIBedWarSetting:show(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.openSetting)
    end
    self.super.show(self)
end

function UIBedWarSetting:hide(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.closeSetting)
    end
    self.super.hide(self)
end

function UIBedWarSetting:changeTabStatus(changeIndex)
    local curTab = self.Tabs[changeIndex]
    local checked = curTab:GetChecked()
    if checked then
        for index, tabCheckBox in pairs(self.Tabs) do
            tabCheckBox:SetChecked(index == changeIndex)
            self.Panel[index]:setVisible(index == changeIndex)
        end
    else
        local needCheck = true
        for _, tabCheckBox in pairs(self.Tabs) do
            if tabCheckBox:GetChecked() then
                needCheck = false
            end
        end
        if needCheck then
            curTab:SetChecked(true)
            return
        end
    end
end

