end

function UIBedWarSetting:initCacheSetting()
    self.defaultSetting = FileUtil.getConfigFromYml("setting/DefaultSettings")
    SystemSettingRecord = {}
    local SettingJson = ClientHelper.getStringForKey(tostring(Game:getPlatformUserId()) .. "g1008_SystemSettings", "")
    if string.sub(SettingJson, 1, 1) == "{" then
        SystemSettingRecord = json.decode(SettingJson)
    end
    self:initSystemSetting(SystemSettingRecord)
end

function UIBedWarSetting:initSystemSetting(setting)
    local oldSetting = TableUtil.copyTable(setting)
    ---帧数默认选择{ 1, 2 ,3}
    local defaultFPS = setting.defaultFPS or self.defaultSetting.defaultFPS
    self.llBasic.fpsGroup:selectIndex(defaultFPS)
    ---视角默认选择{ 1, 2 ,3}
    if GameType == "g1046" then
        self.llBasic.cameraGroup:selectIndex(2)
    else
        self.llBasic.cameraGroup:selectIndex(1)
    end
    ---亮度进度条 [0-1]
    local defaultLuminance = setting.defaultLuminance or self.defaultSetting.defaultLuminance
    self.llBasic:refreshLuminance(defaultLuminance)
    ---按钮大小进度条 [0-1]
    local defaultButtonSize = setting.defaultButtonSize or self.defaultSetting.defaultButtonSize
    self.llBasic:refreshSize(defaultButtonSize)
    ---灵敏度进度条 [0-1]
    local defaultSensitivity = setting.defaultSensitivity or self.defaultSetting.defaultSensitivity
    self.llBasic:refreshSensitive(defaultSensitivity)
    ---视野距离进度条 [0-1]
    local defaultHorizon = setting.defaultHorizon or self.defaultSetting.defaultHorizon
    self.llBasic:refreshHorizon(defaultHorizon)
    ---操作遥感选择{ 1, 2 ,3} 3是灵活摇杆,2是旧摇杆
    local defaultOperation = setting.defaultOperation or self.defaultSetting.defaultOperation
    self.llOperation.opGroup:selectIndex(defaultOperation)
    ---背景音乐开关{ 0, 1} 2是关 1是开
    local defaultBackGroundSwitch = setting.defaultBackGroundSwitch or self.defaultSetting.defaultBackGroundSwitch
    self.llSound.bgGroup:selectIndex(defaultBackGroundSwitch)
    ---背景音乐大小进度条 [0-1]
    local defaultBackGroundVolume = setting.defaultBackGroundVolume or self.defaultSetting.defaultBackGroundVolume
    self.llSound:refreshBackGround(defaultBackGroundVolume)
    ---音效开关{ 0, 1} 2是关 1是开
    local defaultEffectSwitch = setting.defaultEffectSwitch or self.defaultSetting.defaultEffectSwitch
    self.llSound.soundGroup:selectIndex(defaultEffectSwitch)
    ---音效大小进度条 [0-1]
    local defaultEffectVolume = setting.defaultEffectVolume or self.defaultSetting.defaultEffectVolume
    self.llSound:refreshEffect(defaultEffectVolume)
    SystemSettingRecord = oldSetting
end

function UIBedWarSetting:getSystemSettingRecord()
    local setting = {}
    for key, value in pairs(SystemSettingRecord) do
        setting[key] = math.floor(value * 10) / 10
    end
    return setting
end

function UIBedWarSetting:close()
    self:hide(true)
end

---判断是否是第一视角
function UIBedWarSetting:isFirstPerspective()
    return self.llBasic.cameraGroup:getCurIndex() == 1
end

function UIBedWarSetting:changeCamera(index)
    self.llBasic.cameraGroup:selectIndex(index)
end

return UIBedWarSetting